sql:
SELECT state, COUNT(agency_id) AS num_agencies
FROM federal_agency
GROUP BY state;

external_knowledge:
- "beacons of innovation" refers to applicants who stand out in terms of federal funding received;
- "sunlight from federal funding" is a metaphor for the federal share of funding;
- "torch(es)" symbolizes individual projects undertaken by applicants;
- "radiance" is a metaphor for the average cost of projects;
- The top three refers to the limit of 3 in the SQL query.

- 'vessels' metaphorically refers to applications;
- 'unique banner' represents each unique application identified by `application_id`;
- 'identity of the vessels' relates to the `applicant_name`;
- 'average wave they've navigated through' symbolizes the average scores (`average_score`) that applications have received.

sql:
SELECT a.applicant_name, app.status
FROM applicants a
INNER JOIN applications app ON a.applicant_id = app.applicant_id;

SELECT application_id 
FROM applications 
WHERE total_cost > (SELECT AVG(total_cost) FROM applications);

SELECT AVG(num_applications) AS average_applications
FROM (
    SELECT applicant_id, COUNT(application_id) AS num_applications
    FROM applications
    GROUP BY applicant_id
) AS subquery;

SELECT COUNT(application_id) 
FROM applications 
WHERE applicant_id = 1;

SELECT DISTINCT a.applicant_name
FROM applicants a
JOIN applications ap ON a.applicant_id = ap.applicant_id
WHERE ap.total_cost > (
    SELECT AVG(total_cost) FROM applications
);

SELECT application_id, date 
FROM applications 
WHERE date < '2022-01-01';
